const countNeighbors = (cell: [number, number], cells: [number, number][]): number => {
  const [x, y] = cell;
  let neighborCount = 0;
  for (const [cx, cy] of cells) {
    if (cx === x && cy === y) continue;
    if (Math.abs(cx - x) <= 1 && Math.abs(cy - y) <= 1) neighborCount++;
  }
  return neighborCount;
};

export function nextGeneration(cells: [number, number][]): [number, number][] {
  return cells.filter(cell => {
    const neighborCount = countNeighbors(cell, cells);
    return neighborCount === 2 || neighborCount === 3;
  });
}

